screen_content__adas_main_description = TextObject(de_DE="We have the ambition to enhance driving safety by provision of optimized ADAS functions , which serve directly towards the users.\nBy tapping accept, you agree to support us to realize the targets by collecting and processing the data within your vehicle. The\ndecline of collection and processing of aforesaid data will not impair your use of ADAS functions. This includes your general personal\ninformation as well as various technical data required only to optimize the ADAS functions. If you no longer want these data to be\ncollected and processed, you can always change your preference in the general driver assistance systems settings.")
screen_content__adas_sensitive_description = TextObject(de_DE="To provision of optimized ADAS functions, we would also need to collect and process your sensitive personal information which\nincludes the data listed as below, as permitted by Person Information Protection Law of PRC. We will take security measures\nrequired by laws and regulations to protect the sensitive personal information. If you would like to grant us the consent to collect\nand process, please tap the accept button. You can also apply an expiration time for your consent. It is 12 months by default.")
screen_content__camera_description = TextObject(de_DE="In order to use ADAS relevant functions in a holistic way, please manually switch ON the Driver monitor Camera by tap the “Accept”.\nDuring the activation period you can always switch off the Driver Monitor Camera which is located in the ADAS setting page.")
